import{_ as a,o as n,c as t,a3 as o}from"./chunks/framework.CjquFG0V.js";const u=JSON.parse('{"title":"51. Annual Leave","description":"","frontmatter":{"title":"51. Annual Leave","eba":"Biomedical Engineers 2025-2028","topics":["leave","annual-leave","hours","employment"]},"headers":[],"relativePath":"ebas/biomedical-engineers/leave/51-annual-leave.md","filePath":"ebas/biomedical-engineers/leave/51-annual-leave.md"}'),r={name:"ebas/biomedical-engineers/leave/51-annual-leave.md"};function i(s,e,l,p,d,h){return n(),t("div",null,[...e[0]||(e[0]=[o('<h1 id="_51-annual-leave" tabindex="-1">51. Annual Leave <a class="header-anchor" href="#_51-annual-leave" aria-label="Permalink to &quot;51. Annual Leave&quot;">​</a></h1><p><strong>51.1</strong> Basic Entitlement</p><p><strong>(a)</strong> On and from the FFPPOOA 1 August 2024, an Employee (other than a casual Employee) is entitled to 5 weeks (190 hours) annual leave for each year of service with the Employer.</p><p><strong>(b)</strong> Part-time Employees will be entitled to annual leave on a pro rata basis.</p><p><strong>(c)</strong> Annual leave accrues progressively during a year of service according to the Employee’s ordinary hours of work and accumulates from year to year.</p><p><strong>51.2</strong> Weekend Worker Definition For the purposes of this clause, weekend worker means any Employee who in any one year of employment works a portion of their ordinary hours on a weekend.</p><p><strong>51.3</strong> Additional Leave</p><p><strong>(a)</strong> On-call 10 or more weekends</p><p><strong>(i)</strong> An Employee who is rostered on-call for more than four (4) hours on 10 or more weekends per annum will be entitled to an additional 38 hours annual leave (pro rata for part-time Employees).</p><p><strong>(ii)</strong> This entitlement is in addition to the Weekend Worker entitlement provided by subclause 51.3(b), but both entitlements cannot be claimed for the same bodies of work.</p><p><strong>(b)</strong> Weekend Worker</p><p><strong>(i)</strong> An Employee who is a Weekend Worker who works for more than four ordinary hours on 10 or more weekends per year of continuous service is entitled to an additional 38 hours annual leave.</p><p><strong>(ii)</strong> Where an Employee who is a Weekend Worker does not meet the 10 weekend threshold in subclause 51.3(b)(i) above, they will accrue additional annual leave at the rate of one tenth of a week (3.8 hours) for each weekend worked, up to a maximum of one week (38 hours) in a year.</p><p><strong>(iii)</strong> The provisions of this clause have the same effect and give an Employee an entitlement to annual leave that is the same as the entitlement of the Employee under the NES relating to shiftworkers under section 87(1)(b)(ii) of the Act. For the purposes of the NES only, a shiftworker is an Employee who is regularly rostered to work Sundays and public holidays.</p><p><strong>(iv)</strong> An Employee’s entitlement to annual leave under this clause operates in parallel with the Employee’s NES entitlement, but not so as to give the Employee a double benefit.</p><p><strong>(v)</strong> A Weekend Worker whose employment is terminated at the end of a period of employment which is less than one year computed from the date of commencement of the employment, or the date upon which the Employee last became entitled to annual leave from the Employer, will be paid in addition to any other amounts due to the Employee, an amount equal to 1/48th of his or her ordinary pay in respect of that period of employment.</p><p><strong>(vi)</strong> This entitlement is additional to the On-Call 10 or more weekends entitlement provided by subclause 51.3(a), but both entitlements cannot be claimed for the same bodies of work.</p><p><strong>51.4</strong> Leave to be taken Except as provided for by <a href="/eba/ebas/biomedical-engineers/leave/52-cashing-out-of-annual-leave.html">clause 52</a> (Cashing Out of Annual Leave) payment shall not be made or accepted in lieu of annual leave.</p><p><strong>51.5</strong> Time of Taking leave</p><p><strong>(a)</strong> Annual leave may be taken for a period agreed between the Employee and the Employer. An Employee may access accrued annual leave prior to the completion of a year of service.</p><p><strong>(b)</strong> The Employer will not unreasonably refuse to agree to a request by the Employee to take paid annual leave, including a request to take single day or part day periods of annual leave.</p><p><strong>(c)</strong> Leave applications for non-High Demand Holiday Periods</p><p><strong>(i)</strong> An Employee will submit a written request for annual leave as soon as reasonably practicable prior to the first day of the proposed leave period/s.</p><p><strong>(ii)</strong> The Employer will respond to such an application as soon as possible, but no later than 2 weeks after the application has been made.</p><p><strong>(iii)</strong> If the annual leave application is not approved, the Employer will provide the reasons for the leave not being approved.</p><p><strong>(iv)</strong> Nothing in this clause prevents the application by an Employee for ad hoc annual leave for short periods (including a day or part-day) with less than 2</p><p>weeks’ notice. In such situations, an Employer will make genuine attempts to respond as soon as possible.</p><p><strong>(d)</strong> Leave applications for High Demand Holiday Periods</p><p><strong>(i)</strong> An Employer will develop and publish to affected Employees requirements for a high demand holiday period. Where this occurs, the requirement must: <strong>(A)</strong> identify the high demand holiday period; <strong>(B)</strong> identify the date by which a written request for annual leave should be submitted; and <strong>(C)</strong> identify the date by which the Employer will notify the Employee in writing that their annual leave request is approved or, if not approved, the reasons for the leave not being approved.</p><p><strong>(ii)</strong> In determining applications for high-demand periods, the Employer will consider all the circumstances including but not limited to: <strong>(A)</strong> the Employer&#39;s operational needs; <strong>(B)</strong> the Employee&#39;s family responsibilities; and <strong>(C)</strong> whether previous leave applications for the same high demand period were or were not successful.</p><p>Example: A department generally receives more applications for annual leave over school term breaks than it can accommodate. This means that school term breaks are ‘high demand periods’ for that department within the meaning of this subclause 51.5(d) and the Employer must publish the information specified above at subclause 51.5(d)(i) and, when determining the applications, apply the considerations at subclause 51.5(d)(ii).</p><p><strong>51.6</strong> Leave in advance</p><p><strong>(a)</strong> The Employer may allow an Employee to take annual leave in advance of accrual.</p><p><strong>(b)</strong> Where the Employee remains in annual leave debt upon termination, such amount (including any leave loading paid) may be deducted from any amounts otherwise payable to the Employee upon termination of employment.</p><p><strong>51.7</strong> Payment for period of annual leave</p><p><strong>(a)</strong> Employees will receive their ordinary pay and any amount required by subclause</p><p><strong>51.8</strong> (annual leave loading) for the period of leave so taken in the ordinary pay period.</p><p><strong>(b)</strong> Ordinary pay, for the purposes of this clause, means remuneration for the Employee’s weekly number of hours, calculated at the ordinary time rate of pay pursuant to <a href="/eba/ebas/allied-health/appendices/2-wage-rates.html">Appendix 2</a>.</p><p><strong>51.8</strong> Annual Leave loading During annual leave, an Employee shall receive the following payments in addition to their ordinary pay:</p><p><strong>(a)</strong> An Employee, other than a Shiftworker</p><p><strong>(i)</strong> For an Employee classified at Class 4 - 1st Year or below, the allowance will be calculated as 17.5% of their minimum rate of pay and shall be paid at the time leave is taken.</p><p><strong>(ii)</strong> For an Employee classified higher than Class 4 - 1st Year, the allowance will be calculated as 17.5% of the Class 4 – 1st Year minimum rate of pay.</p><p><strong>(b)</strong> Shiftworkers</p><p><strong>(i)</strong> A shiftworker will be paid the higher of: <strong>(A)</strong> the 17.5% allowance prescribed in subclause 51.8(a); or <strong>(B)</strong> the weekend and shift penalties the Employee would have received had they not been on leave during the relevant period.</p><p><strong>51.9</strong> Leave paid on termination If, when the employment of an Employee ends, the Employee has a period of untaken accrued annual leave, the Employer must pay the Employee the amount that would have been payable to the Employee had they taken the period of accrued annual leave, including any annual leave loading.</p><p><strong>51.10</strong> Excess Annual Leave</p><p><strong>(a)</strong> An Employee has an excessive leave accrual if the Employee has accrued more than 8 weeks’ paid annual leave (or 10 weeks’ paid annual leave for a Weekend Worker, as defined by subclause 51.2).</p><p><strong>(b)</strong> If an Employee has an excessive leave accrual, the Employer or the Employee may seek to confer with the other and genuinely try to reach agreement on how to reduce or eliminate the excessive leave accrual.</p><p><strong>(c)</strong> Direction by Employer that leave be taken</p><p><strong>(i)</strong> If an Employer has genuinely tried to reach agreement with an Employee under subclause 51.10(b) but agreement is not reached (including because the Employee refuses to confer), the Employer may direct the Employee in writing to take one or more periods of paid annual leave.</p><p><strong>(ii)</strong> However, a direction by the Employer under subclause 51.10(c)(i): <strong>(A)</strong> is of no effect if it would result at any time in the Employee’s remaining accrued entitlement to paid annual leave being less than 6 weeks when any other paid annual leave arrangements are taken into account; and <strong>(B)</strong> must not require the Employee to take any period of paid annual leave of less than one week; and <strong>(C)</strong> must not require the Employee to take a period of paid annual leave beginning less than 8 weeks, or more than 12 months, after the direction is given; and <strong>(D)</strong> must not be inconsistent with any leave arrangement agreed by the Employer and Employee.</p><p><strong>(iii)</strong> The Employee must take paid annual leave in accordance with a direction under subclause 51.10(c)(i) that is in effect.</p><p><strong>(iv)</strong> An Employee to whom a direction has been given under clause 51.10(c)(i) may request to take a period of paid annual leave as if the direction had not been given. NOTE: the Employer must not unreasonably refuse to agree to a request by the Employee to take paid annual leave.</p><p><strong>(d)</strong> Request by Employee for leave</p><p><strong>(i)</strong> If an Employee has genuinely tried to reach agreement with an Employer under subclause 51.10(b) but agreement is not reached (including because</p><p>the Employer refuses to confer), the Employee may give a written notice to the Employer requesting to take one or more periods of paid annual leave.</p><p><strong>(ii)</strong> However, an Employee may only give a notice to the Employer under subclause 51.10(d)(i) if: <strong>(A)</strong> the Employee has had an excessive leave accrual for more than 6 months at the time of giving the notice; and <strong>(B)</strong> the Employee has not been given a direction under subclause 51.10(c)(i) that, when any other paid annual leave arrangements are taken into account, would eliminate the Employee’s excessive leave accrual.</p><p><strong>(iii)</strong> A notice given by an Employee under subclause 51.10(d)(i) must not: <strong>(A)</strong> if granted, result in the Employee’s remaining accrued entitlement to paid annual leave being at any time less than 6 weeks when any other paid annual leave arrangements are taken into account; or <strong>(B)</strong> provide for the Employee to take any period of paid annual leave of less than one week; or <strong>(C)</strong> provide for the Employee to take a period of paid annual leave beginning less than 8 weeks, or more than 12 months, after the notice is given; or <strong>(D)</strong> be inconsistent with any leave arrangement agreed by the Employer and Employee.</p><p><strong>(iv)</strong> An Employee is not entitled to request by a notice under subclause 51.10(d)(i) more than 4 weeks’ paid annual leave (or 5 weeks’ paid annual leave for a Weekend Worker, as defined by subclause 51.2) in any period of 12 months.</p><p><strong>(v)</strong> The Employer must grant paid annual leave requested by a notice under subclause 51.10(d)(i).</p><p><strong>51.11</strong> Employee not taken to be on paid annual leave at certain times</p><p><strong>(a)</strong> Public Holidays If an Employee takes paid annual leave during a period that includes a public holiday, the Employee is taken not to be on paid annual leave on that day and annual leave will not be deducted from an Employee’s accrual for that day.</p><p><strong>(b)</strong> Other Periods of Leave</p><p><strong>(i)</strong> If a period during which an Employee takes paid annual leave includes a period of any other leave (other than unpaid parental leave) under Part 2-2 of the Act (the National Employment Standards), or a period of absence from employment under Division 8 of Part 2-2 of the Act (which deals with community service leave), the Employee is taken not to be on paid annual leave for the period of that other leave or absence.</p><p><strong>(ii)</strong> If the Employer so requires, the Employee must give the Employer evidence that would satisfy a reasonable person that the other leave taken is for a reason specified in <a href="/eba/ebas/biomedical-engineers/leave/54-personal-carer-s-leave.html">clause 54.1</a> (Personal/Carers Leave) or <a href="/eba/ebas/biomedical-engineers/leave/57-compassionate-leave.html">clause 57</a> (Compassionate Leave) of this Agreement, as the case may be. An Employee is not entitled to take leave under <a href="/eba/ebas/biomedical-engineers/leave/54-personal-carer-s-leave.html">clause 54.1</a> or <a href="/eba/ebas/biomedical-engineers/leave/57-compassionate-leave.html">clause 57</a> unless they comply with any such requirement. Where an Employee complies with these provisions the number of days specified in the required evidence shall be deducted from any personal/carer’s leave entitlement standing to the Employee’s credit, and shall be re-credited to their annual leave entitlement.</p><p><strong>(iii)</strong> The amount of annual leave loading received for any period of annual leave converted to any other form of leave in accordance with clause 51.11(b)(i) shall be deducted from any future entitlement to annual leave loading, or if the Employee resigns, from termination pay.</p><p>Plain language terms: holidays, vacation.</p>',67)])])}const c=a(r,[["render",i]]);export{u as __pageData,c as default};
